49: void finalizeHeaders(FilterManagerCallbacks& callbacks, StreamInfo::StreamInfo& stream_info,
50:                      ResponseHeaderMap& headers) {
51:   const Router::RouteConstSharedPtr& route = stream_info.route();
52:   if (route != nullptr && route->routeEntry() != nullptr) {
53:     const Formatter::Context formatter_context{
54:         callbacks.requestHeaders().ptr(), &headers, {}, {}, {}, &callbacks.activeSpan()};
55:     route->routeEntry()->finalizeResponseHeaders(headers, formatter_context, stream_info);
56:   }
57: }
