148: bool ActiveStreamFilterBase::commonHandleAfter1xxHeadersCallback(Filter1xxHeadersStatus status) {
149:   ASSERT(parent_.state_.has_1xx_headers_);
150:   ASSERT(!continued_1xx_headers_);
151:   ASSERT(canIterate());
152: 
153:   switch (status) {
154:   case Filter1xxHeadersStatus::Continue:
155:     continued_1xx_headers_ = true;
156:     return true;
157:   case Filter1xxHeadersStatus::StopIteration:
158:     iteration_state_ = IterationState::StopSingleIteration;
159:     return false;
160:   }
161: 
162:   PANIC_DUE_TO_CORRUPT_ENUM;
163: }
164: 
165: bool ActiveStreamFilterBase::commonHandleAfterHeadersCallback(FilterHeadersStatus status,
166:                                                               bool& end_stream) {
167:   ASSERT(!headers_continued_);
168:   ASSERT(canIterate());
169: 
170:   switch (status) {
171:   case FilterHeadersStatus::StopIteration:
172:     iteration_state_ = IterationState::StopSingleIteration;
173:     break;
174:   case FilterHeadersStatus::StopAllIterationAndBuffer:
175:     iteration_state_ = IterationState::StopAllBuffer;
176:     break;
177:   case FilterHeadersStatus::StopAllIterationAndWatermark:
178:     iteration_state_ = IterationState::StopAllWatermark;
179:     break;
180:   case FilterHeadersStatus::ContinueAndDontEndStream:
181:     end_stream = false;
182:     headers_continued_ = true;
183:     ENVOY_STREAM_LOG(debug, "converting to headers and body (body not available yet)", parent_);
184:     break;
185:   case FilterHeadersStatus::Continue:
186:     headers_continued_ = true;
187:     break;
188:   }
189: 
190:   handleMetadataAfterHeadersCallback();
191: 
192:   if (stoppedAll() || status == FilterHeadersStatus::StopIteration) {
193:     return false;
194:   } else {
195:     return true;
196:   }
197: }
