141: 
142:         // Test not charging stats on the second call.
143:         if (data.length() == 4) {
144:           RequestHeaderMapPtr headers{new TestRequestHeaderMapImpl{
145:               {":authority", "host"}, {":path", "/"}, {":method", "GET"}}};
