151:         }
152: 
153:         ResponseHeaderMapPtr response_headers{new TestResponseHeaderMapImpl{{":status", "200"}}};
154:         filter->callbacks_->streamInfo().setResponseCodeDetails("");
155:         filter->callbacks_->encodeHeaders(std::move(response_headers), true, "details");
156:         response_encoder_.stream_.codec_callbacks_->onCodecEncodeComplete();
157: 
158:         // Drain 2 so that on the 2nd iteration we will hit zero.
159:         data.drain(2);
160:         return Http::okStatus();
161:       }));
162: 
163:   // Kick off the incoming data. Use extra data which should cause a redispatch.
164:   Buffer::OwnedImpl fake_input("1234");
165:   conn_manager_->onData(fake_input, false);
166: 
167:   // At the end of this, the handle is on the deferred delete list but not
168:   // deleted. It should be invalid.
169:   EXPECT_FALSE(decoder_handle->get().has_value());
170:   filter_callbacks_.connection_.dispatcher_.clearDeferredDeleteList();
171:   EXPECT_FALSE(decoder_handle->get().has_value());
172: 
173:   EXPECT_EQ(1U, stats_.named_.downstream_rq_2xx_.value());
174:   EXPECT_EQ(1U, listener_stats_.downstream_rq_2xx_.value());
175:   EXPECT_EQ(1U, stats_.named_.downstream_rq_completed_.value());
176:   EXPECT_EQ(1U, listener_stats_.downstream_rq_completed_.value());
177: }
