219: ConnectionManagerImpl::~ConnectionManagerImpl() {
220:   stats_.named_.downstream_cx_destroy_.inc();
221: 
222:   stats_.named_.downstream_cx_active_.dec();
223:   if (read_callbacks_->connection().ssl()) {
224:     stats_.named_.downstream_cx_ssl_active_.dec();
225:   }
226: 
227:   if (codec_) {
228:     if (codec_->protocol() == Protocol::Http2) {
229:       stats_.named_.downstream_cx_http2_active_.dec();
230:     } else if (codec_->protocol() == Protocol::Http3) {
231:       stats_.named_.downstream_cx_http3_active_.dec();
232:     } else {
233:       stats_.named_.downstream_cx_http1_active_.dec();
234:     }
235:   }
236: 
237:   if (soft_drain_http1_) {
238:     stats_.named_.downstream_cx_http1_soft_drain_.dec();
239:   }
240: 
241:   conn_length_->complete();
242:   user_agent_.completeConnectionLength(*conn_length_);
243: }
