769: void ConnectionManagerImpl::onConnectionDurationTimeout() {
770:   ENVOY_CONN_LOG(debug, "max connection duration reached", read_callbacks_->connection());
771:   stats_.named_.downstream_cx_max_duration_reached_.inc();
772:   if (!codec_) {
773:     // Attempt to write out buffered data one last time and issue a local close if successful.
774:     doConnectionClose(Network::ConnectionCloseType::FlushWrite,
775:                       StreamInfo::CoreResponseFlag::DurationTimeout,
776:                       StreamInfo::ResponseCodeDetails::get().DurationTimeout);
777:   } else if (drain_state_ == DrainState::NotDraining) {
778:     if (config_->http1SafeMaxConnectionDuration() && codec_->protocol() < Protocol::Http2) {
779:       ENVOY_CONN_LOG(debug,
780:                      "HTTP1-safe max connection duration is configured -- skipping drain sequence.",
781:                      read_callbacks_->connection());
782:       stats_.named_.downstream_cx_http1_soft_drain_.inc();
783:       soft_drain_http1_ = true;
784:     } else {
785:       startDrainSequence();
786:     }
787:   }
