505: Network::FilterStatus ConnectionManagerImpl::onData(Buffer::Instance& data, bool) {
506:   requests_during_dispatch_count_ = 0;
507:   if (!codec_) {
508:     // Close connections if Envoy is under pressure, typically memory, before creating codec.
509:     if (hcm_ondata_creating_codec_ != nullptr && hcm_ondata_creating_codec_->shouldShedLoad()) {
510:       stats_.named_.downstream_rq_overload_close_.inc();
511:       handleCodecOverloadError("onData codec creation overload");
512:       return Network::FilterStatus::StopIteration;
513:     }
514:     // Http3 codec should have been instantiated by now.
515:     createCodec(data);
516:   }
517: 
518:   bool redispatch;
519:   do {
520:     redispatch = false;
521: 
522:     const Status status = codec_->dispatch(data);
523: 
524:     if (isBufferFloodError(status) || isInboundFramesWithEmptyPayloadError(status)) {
525:       handleCodecError(status.message());
526:       return Network::FilterStatus::StopIteration;
527:     } else if (isCodecProtocolError(status)) {
528:       stats_.named_.downstream_cx_protocol_error_.inc();
529:       handleCodecError(status.message());
530:       return Network::FilterStatus::StopIteration;
531:     } else if (isEnvoyOverloadError(status)) {
532:       stats_.named_.downstream_rq_overload_close_.inc();
533:       handleCodecOverloadError(status.message());
534:       return Network::FilterStatus::StopIteration;
535:     }
536:     ASSERT(status.ok());
537: 
538:     // Processing incoming data may release outbound data so check for closure here as well.
539:     checkForDeferredClose(false);
540: 
541:     // The HTTP/1 codec will pause dispatch after a single message is complete. We want to
542:     // either redispatch if there are no streams and we have more data. If we have a single
543:     // complete non-WebSocket stream but have not responded yet we will pause socket reads
544:     // to apply back pressure.
545:     if (codec_->protocol() < Protocol::Http2) {
546:       if (read_callbacks_->connection().state() == Network::Connection::State::Open &&
547:           data.length() > 0 && streams_.empty()) {
548:         redispatch = true;
549:       }
550:     }
551:   } while (redispatch);
552: 
553:   if (!read_callbacks_->connection().streamInfo().protocol()) {
554:     read_callbacks_->connection().streamInfo().protocol(codec_->protocol());
555:   }
556: 
557:   return Network::FilterStatus::StopIteration;
558: }
