49: // Specialization needed for HeaderMapImpl::HeaderList::insert() when key is LowerCaseString.
50: // A fully specialized template must be defined once in the program, hence this may not be in
51: // a header file.
52: template <> bool HeaderMapImpl::HeaderList::isPseudoHeader(const LowerCaseString& key) {
53:   return key.get().c_str()[0] == ':';
