20: // Filter stops headers iteration without ending the stream, then injects a body later.
21: TEST_F(HttpConnectionManagerImplTest, FilterStopIterationInjectBody) {
22:   setup();
23:   setupFilterChain(2, 2);
24: 
25:   // Decode filter 0 changes end_stream to false.
26:   EXPECT_CALL(*decoder_filters_[0], decodeHeaders(_, true))
27:       .WillOnce(Return(FilterHeadersStatus::StopIteration));
28:   EXPECT_CALL(*decoder_filters_[0], decodeComplete());
29:   EXPECT_CALL(*decoder_filters_[1], decodeHeaders(_, false))
30:       .WillOnce(Return(FilterHeadersStatus::Continue));
31: 
32:   // Kick off the incoming data.
33:   startRequest(true);
34: 
35:   EXPECT_CALL(*decoder_filters_[1], decodeData(_, true))
36:       .WillOnce(Return(FilterDataStatus::Continue));
37:   EXPECT_CALL(*decoder_filters_[1], decodeComplete());
38: 
39:   // Decode filter 0 injects request body later.
40:   Buffer::OwnedImpl data("hello");
41:   decoder_filters_[0]->callbacks_->injectDecodedDataToFilterChain(data, true);
42: 
43:   // Encode filter 1 changes end_stream to false.
44:   EXPECT_CALL(*encoder_filters_[1], encodeHeaders(_, true))
45:       .WillOnce(Return(FilterHeadersStatus::StopIteration));
46:   EXPECT_CALL(*encoder_filters_[1], encodeComplete());
47:   EXPECT_CALL(*encoder_filters_[0], encodeHeaders(_, false))
48:       .WillOnce(Return(FilterHeadersStatus::Continue));
49:   EXPECT_CALL(response_encoder_, encodeHeaders(_, false));
50: 
51:   decoder_filters_[1]->callbacks_->streamInfo().setResponseCodeDetails("");
52:   decoder_filters_[1]->callbacks_->encodeHeaders(
53:       makeHeaderMap<TestResponseHeaderMapImpl>({{":status", "200"}}), true, "details");
54: 
55:   EXPECT_CALL(*encoder_filters_[0], encodeData(_, true))
56:       .WillOnce(Return(FilterDataStatus::Continue));
57:   EXPECT_CALL(*encoder_filters_[0], encodeComplete());
58:   EXPECT_CALL(response_encoder_, encodeData(_, true));
59:   expectOnDestroy();
60: 
61:   // Encode filter 1 injects request body later.
62:   Buffer::OwnedImpl data2("hello");
63:   encoder_filters_[1]->callbacks_->injectEncodedDataToFilterChain(data2, true);
64: }
